def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = (np.exp(-(ratio * 12)) + 0.05) * (1 + 0.1 * (ratio - 0.7))
        elif 0.4 < ratio <= 0.7:
            score = 0.3 * ratio ** 2 + 0.02
        else:
            acc = 0
            for k in range(1, 8):
                sign = (-1) ** (k + 1)
                acc += sign * (ratio ** (k + 2)) / (k * 2.0)
            score = abs(acc) + 0.03
        neighbors_influence = 0.0
        max_diff_ratio = 0.0
        for offset in range(1, 6):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset + 0.5)
                    mod_weight = weight * (1 - ratio)
                    neighbors_influence += diff_ratio * mod_weight * 0.08
                    if diff_ratio > max_diff_ratio:
                        max_diff_ratio = diff_ratio
        diversity_adjustment = np.log1p(max_diff_ratio * 10) * 0.05
        capacity_factor = capacity ** 0.6
        if capacity_factor == 0:
            capacity_factor = 1
        priority = score + neighbors_influence / capacity_factor - diversity_adjustment
        if priority < 0:
            priority = 0
        if priority > 1.5:
            priority = 1.5
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    median_finite = np.median(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = median_finite * 3
        elif priorities[i] == 0:
            priorities[i] = median_finite * 0.1
    return priorities
